    backgroundColor: '#ecf0f1',
    borderRadius: '4px'
  },
  fileName: {
    fontSize: '13px',
    color: '#2c3e50',
    flex: 1
  },
  removeFileButton: {
    backgroundColor: 'transparent',
    border: 'none',
    color: '#e74c3c',
    cursor: 'pointer',
    fontSize: '16px',
    fontWeight: 'bold',
    padding: '0 5px'
  },
  title: {
    color: '#2c3e50',
    borderBottom: '3px solid #3498db',
    paddingBottom: '10px',
    marginBottom: '0',
    fontSize: '28px'
  },
  section: {
    backgroundColor: '#f8f9fa',
    padding: '20px',
    borderRadius: '8px',
    marginBottom: '25px',
    border: '1px solid #e0e0e0'
  },
  subSection: {
    backgroundColor: '#ffffff',
