    border: '1px solid #3498db'
  },
  sectionTitle: {
    color: '#2c3e50',
    marginTop: 0,
    marginBottom: '20px',
    fontSize: '18px',
    borderBottom: '1px solid #3498db',
    paddingBottom: '5px'
  },
  subSectionTitle: {
    color: '#3498db',
    marginTop: 0,
    marginBottom: '15px',
    fontSize: '16px'
  },
  form: {
    display: 'flex',
