    backgroundColor: 'white',
    cursor: 'pointer'
  },
  checkboxGroup: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: '15px',
    padding: '10px 0'
  },
  checkboxLabel: {
    display: 'flex',
    alignItems: 'center',
    gap: '5px',
    fontSize: '14px',
    cursor: 'pointer'
  },
  buttonGroup: {
    display: 'flex',
    gap: '10px',
    marginTop: '20px'
  },
  submitButton: {
    backgroundColor: '#27ae60',
    color: 'white',
    padding: '15px',
    border: 'none',
    borderRadius: '4px',
    fontSize: '16px',
